#include <stdio.h>
#include <stdlib.h>

#define MAX 100

typedef struct {
    int V;
    int matrix[MAX][MAX];
} GraphMatrix;

void init_matrix(GraphMatrix *g, int v) {
    g->V = v;
    for(int i=0; i<v; i++)
        for(int j=0; j<v; j++)
            g->matrix[i][j] = 0;
}

void add_edge_matrix(GraphMatrix *g, int u, int v) {
    if(u < g->V && v < g->V) {
        g->matrix[u][v] = 1;
        g->matrix[v][u] = 1;  // undirected
    }
}

int is_adjacent_matrix(GraphMatrix *g, int u, int v) {
    return g->matrix[u][v] == 1;
}

int main() {
    GraphMatrix g;
    init_matrix(&g, 4);
    add_edge_matrix(&g, 0, 1);
    add_edge_matrix(&g, 0, 2);
    printf("Edge 0-1: %d\n", is_adjacent_matrix(&g, 0, 1));
    return 0;
}

from collections import defaultdict

class Graph:
    def __init__(self):
        self.graph = defaultdict(list)

    def add_edge(self, u, v):
        self.graph[u].append(v)
        self.graph[v].append(u)  # undirected

    def dfs_component(self, v, visited, component):
        visited[v] = True
        component.append(v)
        for neighbor in self.graph[v]:
            if not visited[neighbor]:
                self.dfs_component(neighbor, visited, component)

    def find_components(self):
        if not self.graph:
            return []
        visited = {v: False for v in self.graph}
        components = []
        for vertex in self.graph:
            if not visited[vertex]:
                component = []
                self.dfs_component(vertex, visited, component)
                components.append(component)
        return components

